// MissionBoard.jsx
import React, { useState } from "react";
import MissionItem from "./MissionItem";

const initialTasks = [
  { id: 1, text: "Đạt 10 điểm", completed: false },
  { id: 2, text: "Tránh 5 ống liên tiếp", completed: false },
  { id: 3, text: "Chơi 3 lượt", completed: false },
];

function MissionBoard() {
  const [tasks, setTasks] = useState(initialTasks);

  const toggleTask = (id) => {
    setTasks((prev) =>
      prev.map((task) =>
        task.id === id ? { ...task, completed: !task.completed } : task
      )
    );
  };

  return (
    <div className="max-w-2xl mx-auto p-4">
      <h2 className="text-2xl font-bold mb-4">Bảng Nhiệm Vụ Flappy Bird</h2>
      <table className="w-full border text-sm bg-white">
        <thead className="bg-yellow-200">
          <tr>
            <th className="py-2 border">#</th>
            <th className="py-2 border">Nội dung</th>
            <th className="py-2 border">Hoàn thành</th>
          </tr>
        </thead>
        <tbody>
          {tasks.map((task, index) => (
            <MissionItem
              key={task.id}
              task={task}
              index={index}
              toggleTask={toggleTask}
            />
          ))}
        </tbody>
      </table>
    </div>
  );
}

export default MissionBoard;
